SELECT o.order_id, o.member_idx, o.order_date, o.total_price, o.status, m.member_id, m.member_name, MIN(b.book_title) AS book_title, MIN(b.cover_image) AS book_cover, COUNT(*) AS book_count FROM orders o JOIN member m ON o.member_idx = m.member_idx JOIN orderitem oi ON o.order_id = oi.order_id JOIN book b ON oi.book_id = b.book_id
AND m.member_id LIKE CONCAT('%', #{member_id}, '%')
AND o.status = #{payment_status}
AND EXISTS ( SELECT 1 FROM delivery d WHERE d.order_id = o.order_id AND d.status_code = #{delivery_status} )
GROUP BY o.order_id ORDER BY o.order_id DESC LIMIT #{offset}, #{perPageNum}

SELECT COUNT(*)
FROM orders o
JOIN member m ON o.member_idx = m.member_idx


    AND m.member_id LIKE CONCAT('%', #{member_id}, '%')


    AND o.status = #{payment_status}


    AND EXISTS (
      SELECT 1 FROM delivery d
      WHERE d.order_id = o.order_id
      AND d.status_code = #{delivery_status}
    )
